content.query:
let passwordResets = AuditLogs
| where TimeGenerated {TimeRange}
| where OperationName has_any ("Reset user password", "Change user password")
| summarize PasswordResets = count();
let sessionRevocations = AuditLogs
| where TimeGenerated {TimeRange}
| where OperationName == "Revoke sign in sessions"
| summarize SessionRevocations = count();
let groupAdditions = AuditLogs
| where TimeGenerated {TimeRange}
| where OperationName == "Add member to group"
| where TargetResources[0].displayName has_any ("SpyCloud", "Blocked", "Restricted", "Compromised", "HighRisk", "MediumRisk")
| summarize GroupAdditions = count();
let accountDisables = AuditLogs
| where TimeGenerated {TimeRange}
| where OperationName == "Disable account"
| summarize AccountsDisabled = count();
let mfaEnforcements = AuditLogs
| where TimeGenerated {TimeRange}
| where OperationName has_any ("Admin registered security info", "Require re-register MFA")
| summarize MFAEnforcements = count();
let defenderAlerts = SecurityAlert
| where TimeGenerated {TimeRange}
| where ProviderName has_any ("MCAS", "MDATP", "Azure Advanced Threat Protection", "Microsoft Defender")
| summarize DefenderAlerts = count();
passwordResets | join sessionRevocations on 1==1 | join groupAdditions on 1==1 | join accountDisables on 1==1 | join mfaEnforcements on 1==1 | join defenderAlerts on 1==1
| project PasswordResets, SessionRevocations, GroupAdditions, AccountsDisabled, MFAEnforcements, DefenderAlerts

let infectedHosts = SpyCloudCompassDevices_CL
| where TimeGenerated {TimeRange}
| distinct user_hostname;
DnsEvents
| where TimeGenerated {TimeRange}
| where Computer in (infectedHosts)
| where Name has_any (".duckdns.org", ".no-ip.com", ".ddns.net", ".hopto.org", ".zapto.org", ".serveftp.com", ".sytes.net")
   or Name matches regex @"^[a-z0-9]{20,}\."
| project TimeGenerated, Computer, Name, IPAddresses, QueryType
| sort by TimeGenerated desc
